// ------ ------ User backend ------ ------
app.post("/registerUser", async (req, res) => {
    
    try {
        const { email, username, password } = req.body;

        const found = await User.findOne({ $or: [{ username: username }, { email: email }] });

        if (!found){
          const newUser = new User({
            
              username: username,
              email: email,
              password: hash(password),
              bio: "Describe yourself...",
              likes: 0,
              //default profile picture converted to base64 String
              profile: "data:image/png;base64,",
              //default banner picture converted to base64 String
              banner: "data:image/jpeg;base64,",
              wins: 0,
              losses: 0,
              ties: 0
          
          });

          await newUser.save();
          //assigning session user
          req.session.user = {
             _id: newUser._id.toString(),
            username: newUser.username,
            email: newUser.email,
            bio: newUser.bio,
            likes: newUser.likes,
            profile: newUser.profile,
            banner: newUser.banner,
            wins: newUser.wins,
            losses: newUser.losses,
            ties: newUser.ties,
            liked_posts_id : newUser.liked_posts_id,
            liked_replies_id: newUser.liked_replies_id,
            disliked_posts_id : newUser.disliked_posts_id,
            disliked_replies_id : newUser.disliked_replies_id,
          };
          
          //saving session info
         req.session.save((err)=>{
          if (err) {
            console.log("broken");
            return res.status(409).json({ success: false, message: "broken" });
          }
          res.redirect("/");
        });     

        }
        else{
          res.redirect("/regErr");
        }
        
    } catch (err) {
        console.error(err);
    }
});

