//READ
app.get("/posts/:page", async (req, res) => {
  const page = parseInt(req.params.page);
  const limit = 15;

  try {
    const posts = await Post.find({})
      .sort({_id: -1})
      .skip((page - 1) * limit)
      .limit(limit);

    res.status(200).json(posts);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});


